mapper.update:
UPDATE TB_PRODUCT
SET PRODUCT_NAME = #{productName}, CATEGORY_ID = #{categoryId}, PRICE = #{price},
    SALE_PRICE = #{salePrice}, DESCRIPTION = #{description},
    BRAND_NAME = #{brandName}, STATUS_CD = #{statusCd}, TAGS = #{tags}
WHERE PRODUCT_ID = #{productId} AND BIZ_NO = #{bizNo}

mapper.select:
SELECT o.ORDER_ID, o.ORDER_NO, o.ORDER_STATUS, o.PAY_AMOUNT, o.ORDER_DATE, m.NICKNAME AS BUYER_NAME, (SELECT oi.PRODUCT_NAME FROM TB_ORDER_ITEM oi WHERE oi.ORDER_ID = o.ORDER_ID AND ROWNUM = 1) AS FIRST_PRODUCT_NAME, (SELECT COUNT(*) FROM TB_ORDER_ITEM oi WHERE oi.ORDER_ID = o.ORDER_ID) AS ITEM_COUNT FROM TB_ORDER o JOIN TB_MEMBER m ON m.MEMBER_NO = o.MEMBER_NO WHERE o.BIZ_NO = #{bizNo}
AND o.CLAIM_STATUS = 'PENDING'
AND o.ORDER_STATUS = #{statusCd}
ORDER BY o.ORDER_ID DESC

mapper.update:
UPDATE TB_ORDER
SET ORDER_STATUS = #{orderStatus}
WHERE ORDER_ID = #{orderId} AND BIZ_NO = #{bizNo}

UPDATE TB_ORDER
SET CLAIM_STATUS = 'DONE', ORDER_STATUS = 'CANCEL', REFUND_AMOUNT = #{refundAmount}
WHERE ORDER_ID = #{orderId} AND BIZ_NO = #{bizNo} AND CLAIM_STATUS = 'PENDING'

UPDATE TB_ORDER_DELIVERY
SET COURIER_NAME = #{courierName}, TRACKING_NO = #{trackingNo}, DELIVERY_STATUS = #{deliveryStatus}, REGISTERED_AT = SYSDATE
WHERE ORDER_ID = #{orderId}

mapper.select:
SELECT o.ORDER_ID, o.ORDER_NO, m.NICKNAME AS BUYER_NAME, d.COURIER_NAME, d.TRACKING_NO, o.ORDER_STATUS, TO_CHAR(d.REGISTERED_AT, 'YYYY-MM-DD') AS SHIP_DATE FROM TB_ORDER o JOIN TB_MEMBER m ON m.MEMBER_NO = o.MEMBER_NO LEFT JOIN TB_ORDER_DELIVERY d ON d.ORDER_ID = o.ORDER_ID WHERE o.BIZ_NO = #{bizNo} AND o.ORDER_STATUS IN ('READY','SHIPPING','DONE')
AND d.COURIER_NAME = #{carrier}
AND o.ORDER_STATUS = #{statusCd}
AND (UPPER(o.ORDER_NO) LIKE '%' || UPPER(#{keyword}) || '%' OR UPPER(m.NICKNAME) LIKE '%' || UPPER(#{keyword}) || '%')
ORDER BY o.ORDER_ID DESC

mapper.update:
UPDATE TB_REVIEW
   SET BIZ_REPLY = #{bizReply}
 WHERE REVIEW_ID = #{reviewId}
   AND REVIEW_TYPE = 'PRODUCT'
   AND TARGET_ID IN (SELECT PRODUCT_ID FROM TB_PRODUCT WHERE BIZ_NO = #{bizNo})

mapper.select:
SELECT q.QNA_ID AS qnaId, q.PRODUCT_ID AS productId, q.MEMBER_NO AS memberNo, q.QUESTION AS question, q.ANSWER AS answer, q.REG_DATE AS regDate, m.NICKNAME AS nickname, p.PRODUCT_NAME AS productName,
f.FILE_URL AS thumbnailUrl, o.OPTION_COLOR AS optionColor, o.OPTION_SIZE AS optionSize, q.ANSWER_DATE AS answerDate FROM TB_PRODUCT_QNA q JOIN TB_MEMBER m ON m.MEMBER_NO = q.MEMBER_NO JOIN TB_PRODUCT p ON p.PRODUCT_ID = q.PRODUCT_ID LEFT JOIN TB_PRODUCT_OPTION o ON o.OPTION_ID = q.OPTION_ID LEFT JOIN ( SELECT REF_ID, FILE_URL, ROW_NUMBER() OVER (PARTITION BY REF_ID ORDER BY FILE_ID) AS RN FROM TB_FILE WHERE REF_TYPE = 'PRODUCT' ) f ON f.REF_ID = p.PRODUCT_ID AND f.RN = 1 WHERE p.BIZ_NO = #{bizNo}
ORDER BY (CASE WHEN q.ANSWER IS NULL THEN 0 ELSE 1 END), q.QNA_ID DESC
